    \begin{equation*}
        \frac{l^{\frac{1}{2}}}{\sqrt{2\pi m}}\cdot\frac{(1+2a)^{\frac{1}{2}}(1+a)a^{\frac{l-2}{2}}}{(1+a)^l-1}\cdot\Big(\frac{1+2a}{1+a}\Big)^{(m+\frac{1}{2})l}.
    \end{equation*}
\end{enumerate}

